python3 << 'EOF'
import json

schema = json.load(open('/input/repo/schema.json'))
results = json.load(open('/workspace/extraction_results.json'))

errors = []
for field_name, field_def in schema['fields'].items():
    expected_type = field_def['type']
    value = results['fields'].get(field_name)

    if expected_type == 'integer':
        if not isinstance(value, int) or isinstance(value, bool):
            errors.append(f"{field_name}: expected integer, got {type(value).__name__} ({value})")
    elif expected_type == 'number':
        if not isinstance(value, (int, float)) or isinstance(value, bool):
            errors.append(f"{field_name}: expected number, got {type(value).__name__} ({value})")
    elif expected_type == 'string':
        if not isinstance(value, str):
            errors.append(f"{field_name}: expected string, got {type(value).__name__} ({value})")
    elif expected_type == 'date':
        if not isinstance(value, str):
            errors.append(f"{field_name}: expected date string, got {type(value).__name__} ({value})")
        else:
            # Check ISO 8601 format
            import re
            if not re.match(r'^\d{4}-\d{2}-\d{2}$', value):
                errors.append(f"{field_name}: date not in ISO 8601 format: {value}")

if errors:
    print("ERRORS:")
    for e in errors:
        print(f"  - {e}")
else:
    print("All 20 fields pass type validation.")
    print(f"Uncertain fields: {results['uncertain']}")
    print(f"Notes: {results['notes'][:80]}...")
EOF
